Initiative ID: init-commed-habitude-20260226-0411

TPM Contract:
{
  "version": "1.0",
  "initiativeCore": {
    "problemStatement": "Users lack a seamless, accessible way to track daily habits and personal goals with timely reminders and visual progress tracking across multiple communication channels.",
    "goals": [
      "Enable users to track daily habits and personal goals",
      "Provide customizable reminders to support habit consistency",
      "Visualize habit-building progress through intuitive charts",
      "Deliver streak notifications to motivate continued engagement",
      "Integrate with SMS, Telegram, and WhatsApp for multi-channel accessibility (one channel per user, selected at signup)",
      "Support bi-directional communication allowing users to mark habits complete via messaging platforms"
    ],
    "nonGoals": [
      "Social features or habit sharing between users (not in initial scope)",
      "Advanced analytics or AI-powered habit recommendations (not in initial scope)",
      "Integration with additional messaging platforms beyond SMS, Telegram, and WhatsApp",
      "Multi-language support beyond English (not in initial scope)",
      "Historical habit completion (backdating entries)",
      "Complex authentication mechanisms beyond messaging channel verification",
      "Changing messaging channel after signup",
      "Offline mode or local data caching",
      "Habit editing or modification after creation",
      "Reminder delivery failure handling or retry mechanisms",
      "Restarting stopped habits"
    ],
    "businessImpact": "Success: Increased user engagement and retention through habit consistency features; potential for premium subscription revenue from advanced features. Failure: Low adoption if reminders are unreliable or integrations fail; user churn if progress tracking lacks value. Note: This is a proof-of-concept with simplified failure handling and authentication.",
    "stakeholders": "Unknown - no stakeholders identified in brief"
  },
  "requirements": {
    "functional": [
      {
        "id": "FR-01",
        "description": "Users can create and manage custom daily habits (maximum 5 habits per user)",
        "priority": "must"
      },
      {
        "id": "FR-02",
        "description": "Users can set and customize reminder schedules for each habit with flexible frequencies (daily, every 2 days, weekly, monthly, hourly intervals: 1h, 6h) and custom time-of-day schedules",
        "priority": "must"
      },
      {
        "id": "FR-03",
        "description": "System displays progress charts visualizing habit completion over time",
        "priority": "must"
      },
      {
        "id": "FR-04",
        "description": "System sends streak notifications when users maintain habit consistency",
        "priority": "should"
      },
      {
        "id": "FR-05",
        "description": "System integrates with SMS for bi-directional reminder delivery and habit completion",
        "priority": "must"
      },
      {
        "id": "FR-06",
        "description": "System integrates with Telegram for bi-directional reminder delivery and habit completion",
        "priority": "must"
      },
      {
        "id": "FR-07",
        "description": "System integrates with WhatsApp for bi-directional reminder delivery and habit completion",
        "priority": "must"
      },
      {
        "id": "FR-08",
        "description": "Users can mark habits as complete for each day via web interface",
        "priority": "must"
      },
      {
        "id": "FR-09",
        "description": "Users can define personal goals associated with habits",
        "priority": "should"
      },
      {
        "id": "FR-10",
        "description": "System tracks and displays current streak count per habit",
        "priority": "should"
      },
      {
        "id": "FR-11",
        "description": "Users can mark habits as complete by replying to reminder messages on SMS, Telegram, or WhatsApp",
        "priority": "must"
      },
      {
        "id": "FR-12",
        "description": "System enforces maximum limit of 5 habits per user",
        "priority": "must"
      },
      {
        "id": "FR-13",
        "description": "System supports multiple reminder frequency options: daily, every 2 days, weekly, monthly, every 1 hour, every 6 hours",
        "priority": "must"
      },
      {
        "id": "FR-14",
        "description": "System parses and processes incoming messages from users to mark habits complete",
        "priority": "must"
      },
      {
        "id": "FR-15",
        "description": "System sends confirmation messages when habits are marked complete via messaging platforms",
        "priority": "should"
      },
      {
        "id": "FR-16",
        "description": "Users must select one messaging channel (SMS, Telegram, or WhatsApp) during signup for receiving reminders",
        "priority": "must"
      },
      {
        "id": "FR-17",
        "description": "System supports English language only for all messages and user interactions",
        "priority": "must"
      },
      {
        "id": "FR-18",
        "description": "Habits can only be marked complete for the current day (no backdating or historical completion)",
        "priority": "must"
      },
      {
        "id": "FR-19",
        "description": "Users can set custom time-of-day schedules with up to 12 times per day",
        "priority": "must"
      },
      {
        "id": "FR-20",
        "description": "System implements messaging channel verification authentication: sends random 6-digit code to user's selected channel, user confirms code to complete signup and login",
        "priority": "must"
      },
      {
        "id": "FR-21",
        "description": "System prevents marking the same habit complete multiple times on the same day",
        "priority": "must"
      },
      {
        "id": "FR-22",
        "description": "Users must select a timezone during signup which the system uses for all reminder scheduling and time-based operations",
        "priority": "must"
      },
      {
        "id": "FR-23",
        "description": "System sends confirmation message in format '[Habit Name] Completed!' when habit is marked complete via messaging platform",
        "priority": "must"
      },
      {
        "id": "FR-24",
        "description": "System persists habit data and streak information in database for long-term storage and retrieval",
        "priority": "must"
      },
      {
        "id": "FR-25",
        "description": "Messaging channel selection is permanent and cannot be changed after signup",
        "priority": "must"
      },
      {
        "id": "FR-26",
        "description": "System accepts replies in format 'Habit (xxxx): done' where xxxx is the habit identifier to mark habits complete via messaging",
        "priority": "must"
      },
      {
        "id": "FR-27",
        "description": "System operates in real-time only with no offline mode or local data caching",
        "priority": "must"
      },
      {
        "id": "FR-28",
        "description": "System immediately cancels all pending reminders when a habit is deleted",
        "priority": "must"
      },
      {
        "id": "FR-29",
        "description": "System ignores replies to outdated reminder messages (messages sent before the most recent reminder for that habit)",
        "priority": "must"
      },
      {
        "id": "FR-30",
        "description": "Habits cannot be edited or modified after creation (no update functionality)",
        "priority": "must"
      },
      {
        "id": "FR-31",
        "description": "Users can stop a habit, which permanently cancels all future reminders for that habit",
        "priority": "must"
      },
      {
        "id": "FR-32",
        "description": "Stopped habits cannot be restarted; users must create a new habit if they want similar functionality",
        "priority": "must"
      },
      {
        "id": "FR-33",
        "description": "System does not implement reminder delivery retry mechanisms or failure handling",
        "priority": "must"
      },
      {
        "id": "FR-34",
        "description": "System generates and sends 6-digit verification code to user's selected messaging channel during signup",
        "priority": "must"
      },
      {
        "id": "FR-35",
        "description": "User confirms 6-digit verification code to complete signup and authentication",
        "priority": "must"
      },
      {
        "id": "FR-36",
        "description": "System authenticates user session after successful verification code confirmation",
        "priority": "must"
      }
    ],
    "nonFunctional": [
      {
        "id": "NFR-01",
        "description": "Reminder delivery must be timely and reliable across all messaging platforms (best-effort, no retry on failure)",
        "priority": "must"
      },
      {
        "id": "NFR-02",
        "description": "User interface must be intuitive and require minimal learning curve",
        "priority": "must"
      },
      {
        "id": "NFR-03",
        "description": "Progress charts must load and render within 2 seconds",
        "priority": "should"
      },
      {
        "id": "NFR-04",
        "description": "System must be accessible on mobile and desktop web browsers",
        "priority": "must"
      },
      {
        "id": "NFR-05",
        "description": "Platform must handle concurrent users without performance degradation",
        "priority": "should"
      },
      {
        "id": "NFR-06",
        "description": "User data must be securely stored and transmitted",
        "priority": "must"
      },
      {
        "id": "NFR-07",
        "description": "Bi-directional message processing must occur within 5 seconds of user reply",
        "priority": "must"
      },
      {
        "id": "NFR-08",
        "description": "System must handle message parsing errors gracefully and provide helpful feedback",
        "priority": "should"
      },
      {
        "id": "NFR-09",
        "description": "6-digit verification codes must be securely generated and validated with appropriate expiration",
        "priority": "must"
      },
      {
        "id": "NFR-10",
        "description": "All user-facing messages must be in English with clear, consistent language",
        "priority": "must"
      },
      {
        "id": "NFR-11",
        "description": "All reminder times must be calculated and delivered according to user's selected timezone",
        "priority": "must"
      },
      {
        "id": "NFR-12",
        "description": "Database must reliably persist habit and streak data with appropriate backup and recovery mechanisms",
        "priority": "must"
      },
      {
        "id": "NFR-13",
        "description": "System must require active internet connection for all operations (no offline functionality)",
        "priority": "must"
      },
      {
        "id": "NFR-14",
        "description": "Reminder cancellation must occur immediately upon habit deletion or stopping to prevent orphaned reminders",
        "priority": "must"
      },
      {
        "id": "NFR-15",
        "description": "Verification code delivery must be reliable across all three messaging platforms",
        "priority": "must"
      },
      {
        "id": "NFR-16",
        "description": "System accepts reminder delivery failures without retry as acceptable for POC scope",
        "priority": "must"
      }
    ],
    "edgeCases": [
      "Messaging platform API is temporarily unavailable during scheduled reminder time (no retry, reminder lost)",
      "User has multiple habits with overlapping reminder times",
      "User deletes a habit with an active streak",
      "User's phone number or messaging account becomes invalid",
      "Streak calculation when user marks habit complete after midnight in their timezone",
      "Chart rendering with incomplete or sparse habit data",
      "User attempts to create duplicate habits",
      "Rate limiting from messaging platform APIs during high-volume reminder periods",
      "User attempts to create more than 5 habits",
      "User replies with ambiguous or unrecognized text to mark habit complete",
      "User marks same habit complete multiple times in same period",
      "Reminder frequency conflicts (e.g., hourly reminders overlapping with daily reminders)",
      "User replies to old reminder messages after new ones have been sent",
      "Bi-directional message processing when webhook endpoints are down",
      "Parsing replies in different languages or with typos",
      "Handling rapid-fire replies from users across multiple habits",
      "Monthly reminder scheduling across months with different day counts",
      "User attempts to mark habit complete for past or future dates",
      "Custom time schedules with times spanning across midnight in user's timezone",
      "User sets overlapping custom times for the same habit",
      "Verification code expiration during user signup flow",
      "User attempts to mark already-completed habit as complete again on same day",
      "User sets exactly 12 custom times and attempts to add more",
      "User changes custom time schedule while reminders are pending",
      "Timezone edge cases: DST transitions, timezone boundaries at midnight",
      "Database connection failures during habit completion or streak updates",
      "User signup with invalid or unsupported timezone",
      "Confirmation message delivery failure after successful habit completion",
      "User attempts to change messaging channel after signup (should be prevented)",
      "Habit data corruption or inconsistency in database",
      "Multiple simultaneous habit completions from different devices",
      "Custom time schedule validation with times in different formats (12h vs 24h)",
      "Reminder scheduling when user's timezone differs significantly from server timezone",
      "User replies with incorrect habit identifier format (not matching 'Habit (xxxx): done')",
      "User loses internet connection while marking habit complete via web interface",
      "Pending reminders exist when habit is deleted (must be cancelled immediately)",
      "User replies to reminder message that was sent before the most recent reminder for that habit",
      "System receives reply to outdated reminder while newer reminder is pending",
      "User deletes habit while reminder is in-flight but not yet delivered",
      "Race condition between habit deletion and reminder delivery",
      "User replies with valid format but non-existent habit identifier",
      "Multiple reminders for same habit sent in quick succession due to custom time schedule",
      "User attempts to use system offline or with intermittent connectivity",
      "User attempts to edit or modify habit after creation (should be prevented)",
      "User stops a habit and then attempts to restart it (should be prevented)",
      "User stops a habit with pending reminders (all future reminders must be cancelled)",
      "User creates new habit identical to previously stopped habit",
      "Verification code delivery fails during signup",
      "User enters incorrect verification code multiple times",
      "User attempts to reuse expired verification code",
      "Multiple signup attempts with same messaging channel identifier",
      "User loses access to messaging channel after signup but before verification",
      "Verification code sent but never confirmed (abandoned signup)",
      "User attempts to verify with code sent to different messaging channel",
      "Reminder delivery fails silently with no retry or user notification"
    ]
  },
  "acceptanceCriteria": {
    "criteria": [
      {
        "id": "AC-01",
        "description": "User can successfully create a new habit with custom name and reminder schedule from available frequency options",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-02",
        "description": "User receives reminder notification via selected messaging platform at scheduled time according to their timezone",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-03",
        "description": "Progress chart displays accurate completion data for the past 30 days",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-04",
        "description": "Streak notification is sent when user completes habit for 3 consecutive days",
        "testable": true,
        "priority": "P1"
      },
      {
        "id": "AC-05",
        "description": "User can mark a habit as complete and see updated streak count immediately",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-06",
        "description": "User interface is intuitive and easy to navigate",
        "testable": false,
        "priority": "P1"
      },
      {
        "id": "AC-07",
        "description": "All three messaging platforms (SMS, Telegram, WhatsApp) successfully deliver reminders",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-08",
        "description": "User can customize reminder frequency and time for each habit independently using supported frequencies",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-09",
        "description": "App empowers users to cultivate positive habits effortlessly",
        "testable": false,
        "priority": "P2"
      },
      {
        "id": "AC-10",
        "description": "User can reply to reminder message on SMS, Telegram, or WhatsApp to mark habit complete",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-11",
        "description": "System prevents user from creating more than 5 habits and displays appropriate error message",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-12",
        "description": "System correctly processes bi-directional messages and updates habit status within 5 seconds",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-13",
        "description": "User receives confirmation message in format '[Habit Name] Completed!' after successfully marking habit complete via messaging platform",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-14",
        "description": "System supports all specified reminder frequencies: daily, every 2 days, weekly, monthly, every 1 hour, every 6 hours",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-15",
        "description": "User must select one messaging channel during signup and cannot change it afterward",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-16",
        "description": "All system messages and user interface text are displayed in English only",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-17",
        "description": "System prevents marking habits complete for past or future dates, only allowing current day completion",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-18",
        "description": "User can set custom time-of-day schedule with up to 12 times per day and receive reminders at each specified time in their timezone",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-19",
        "description": "User receives 6-digit verification code via selected messaging channel during signup",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-20",
        "description": "System prevents duplicate completion of the same habit on the same day",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-21",
        "description": "User selects a timezone during signup and all reminders are scheduled according to that timezone",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-22",
        "description": "System enforces maximum of 12 custom times per habit and prevents adding more",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-23",
        "description": "Habit and streak data persists correctly in database and survives system restarts",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-24",
        "description": "System accepts and correctly processes replies in format 'Habit (xxxx): done' to mark habits complete",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-25",
        "description": "System requires active internet connection and displays appropriate error when offline",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-26",
        "description": "All pending reminders are immediately cancelled when a habit is deleted",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-27",
        "description": "System ignores replies to outdated reminder messages and only processes replies to the most recent reminder for each habit",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-28",
        "description": "System prevents editing or modifying habits after creation",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-29",
        "description": "User can stop a habit and all future reminders are permanently cancelled",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-30",
        "description": "System prevents restarting stopped habits",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-31",
        "description": "User can confirm 6-digit verification code and complete signup/authentication",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-32",
        "description": "System authenticates user session after successful verification code confirmation",
        "testable": true,
        "priority": "P0"
      },
      {
        "id": "AC-33",
        "description": "System accepts reminder delivery failures without implementing retry mechanisms",
        "testable": true,
        "priority": "P0"
      }
    ],
    "measurableOutcomes": [
      "Percentage of users who maintain 7-day streaks",
      "Reminder delivery success rate per messaging platform (best-effort, no retry)",
      "User retention rate after 30 days",
      "Average number of habits tracked per active user (target: 3-5)",
      "Time to complete first habit creation flow",
      "Chart load time performance metrics",
      "Bi-directional message processing success rate",
      "Percentage of habits marked complete via messaging vs web interface",
      "Average response time for bi-directional message processing",
      "Custom time schedule adoption rate (percentage of users using custom times vs preset frequencies)",
      "Verification code delivery success rate across messaging platforms",
      "Percentage of users utilizing custom time schedules vs preset frequencies",
      "Database query performance for habit and streak retrieval",
      "Confirmation message delivery success rate",
      "Timezone-related reminder accuracy (percentage of reminders delivered within 1 minute of scheduled time)",
      "Distribution of messaging channel selection at signup (SMS vs Telegram vs WhatsApp)",
      "Average number of custom times set per habit (target: 2-6 out of maximum 12)",
      "Reply format parsing success rate for 'Habit (xxxx): done' format",
      "Percentage of replies rejected due to outdated reminder message",
      "Reminder cancellation success rate upon habit deletion or stopping",
      "Average time between habit deletion/stopping and complete reminder cancellation",
      "Percentage of habits stopped vs deleted",
      "Rate of new habit creation after stopping previous habits",
      "Verification code confirmation success rate",
      "Average time to complete signup and verification flow",
      "Percentage of abandoned signups (verification code sent but not confirmed)",
      "Reminder delivery failure rate (accepted as normal for POC)"
    ]
  },
  "risksAndDependencies": {
    "internalDependencies": [
      "Backend infrastructure for habit data storage and retrieval",
      "Database system for persisting habit and streak data with backup capabilities",
      "Reminder scheduling and notification service supporting custom time schedules with timezone awareness",
      "Chart rendering library or component",
